#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007

int is_arithmetic_progression(int* arr, int n) {
    if (n < 2) return 0;
    int diff = arr[1] - arr[0];
    for (int i = 1; i < n - 1; i++) {
        if (arr[i + 1] - arr[i] != diff) return 0;
    }
    return 1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int* arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        int count = 0;
        for (int i = 0; i < (1 << n); i++) {
            int subsequence[n];
            int subsequence_size = 0;
            for (int j = 0; j < n; j++) {
                if ((i & (1 << j))) subsequence[subsequence_size++] = arr[j];
            }
            if (subsequence_size > 1 && is_arithmetic_progression(subsequence, subsequence_size)) count++;
        }
        printf("%d\n", count % MOD);
        free(arr);
    }
    return 0;
}

