#include <iostream>
#include <vector>
using namespace std;
#define MOD 1000000007

bool is_arithmetic_progression(vector<int> arr) {
    if (arr.size() < 2) return false;
    int diff = arr[1] - arr[0];
    for (int i = 1; i < arr.size() - 1; i++) {
        if (arr[i + 1] - arr[i] != diff) return false;
    }
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int n;
        cin >> n;
        vector<int> arr(n);
        for (int i = 0; i < n; i++) cin >> arr[i];
        int count = 0;
        for (int i = 0; i < (1 << n); i++) {
            vector<int> subsequence;
            for (int j = 0; j < n; j++) {
                if ((i & (1 << j))) subsequence.push_back(arr[j]);
            }
            if (subsequence.size() > 1 && is_arithmetic_progression(subsequence)) count++;
        }
        cout << (count % MOD) << endl;
    }
    return 0;
}

