import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) arr[i] = sc.nextInt();
            int count = 0;
            for (int i = 0; i < (1 << n); i++) {
                int subsequence[] = new int[n];
                int subsequence_size = 0;
                for (int j = 0; j < n; j++) {
                    if ((i & (1 << j)) != 0) subsequence[subsequence_size++] = arr[j];
                }
                if (subsequence_size > 1 && is_arithmetic_progression(subsequence, subsequence_size)) count++;
            }
            System.out.println(count % MOD);
        }
    }
    public static boolean is_arithmetic_progression(int[] arr, int n) {
        if (n < 2) return false;
        int diff = arr[1] - arr[0];
        for (int i = 1; i < n - 1; i++) {
            if (arr[i + 1] - arr[i] != diff) return false;
